/**
 * Helper: generate a did:key + signing key pair for tests.
 * Uses ES256 (P-256) which jose can sign/verify directly.
 */
async function generateDidKeyPair() {
  const { publicKey, privateKey } = await jose.generateKeyPair("ES256", { extractable: true });
  const publicJwk = await jose.exportJWK(publicKey);
  publicJwk.alg = "ES256";
  publicJwk.use = "sig";

  // Construct a synthetic did:key identifier from the JWK thumbprint
  const thumbprint = await jose.calculateJwkThumbprint(publicJwk, "sha256");
  const did = `did:key:z${thumbprint}`;
  const kid = `${did}#${thumbprint}`;

  return { did, kid, publicKey, privateKey, publicJwk };
}

/**
 * Helper: create a signed VC-JOSE credential (vc+jwt).
 */
async function createVcJoseCredential({
  did, kid, privateKey,
  agentId = "agent:test-agent-001",
  permissions = ["damage_assessment:read"],
  constraints = [{ type: "NumericLimitConstraint", field: "claimAmount", operator: "lte", value: 5000 }],
  validFromDate = new Date(),
  validUntilDate = new Date(Date.now() + 3600_000),
  credentialStatus = null,
  delegatedFrom = null,
  audience = null,
}) {
  const credentialId = `urn:uuid:test-${Date.now()}`;

  const credentialSubject = {
    id: agentId,
    permissions,
    constraints,
  };
  if (delegatedFrom) credentialSubject.delegatedFrom = delegatedFrom;

  const vc = {
    "@context": ["https://www.w3.org/ns/credentials/v2"],
    type: ["VerifiableCredential", "AgentAuthorizationCredential"],
    issuer: did,
    validFrom: validFromDate.toISOString(),
    validUntil: validUntilDate.toISOString(),
    credentialSubject,
  };
  if (credentialStatus) vc.credentialStatus = credentialStatus;

  const payload = { iss: did, sub: agentId, jti: credentialId, vc };
  if (audience) payload.aud = audience;

  const jwt = await new jose.SignJWT(payload)
    .setProtectedHeader({ typ: "vc+jwt", alg: "ES256", kid })
    .setIssuedAt()
    .setNotBefore(validFromDate)
    .setExpirationTime(validUntilDate)
    .sign(privateKey);

  return { jwt, credentialId, did };
}

